#include <bits/stdc++.h>
using namespace std;

struct Node {
    int data;
    Node* next;
    Node(int x) {
        data = x;
        next = NULL;
    }
};

bool detectLoop(Node* head) {
    if (head == NULL || head->next == NULL)
        return false;

    Node *slow = head, *fast = head;

    while (fast != NULL && fast->next != NULL) {
        slow = slow->next;
        fast = fast->next->next;

        if (slow == fast)
            return true;
    }
    return false;
}

// Helper function to create linked list with loop
Node* createList(vector<int>& arr, int pos) {
    if (arr.empty()) return NULL;

    Node* head = new Node(arr[0]);
    Node* curr = head;
    Node* loop_node = (pos == 1) ? head : NULL;

    for(int i = 1; i < arr.size(); i++) {
        curr->next = new Node(arr[i]);
        curr = curr->next;
        if (i + 1 == pos) loop_node = curr;
    }

    if (pos != 0) curr->next = loop_node;
    return head;
}

int main() {
    int t;
    cin >> t;

    while(t--) {
        int n;
        cin >> n;

        vector<int> arr(n);
        for(int i = 0; i < n; i++) {
            cin >> arr[i];
        }

        int pos;
        cin >> pos;

        Node* head = createList(arr, pos);
        cout << (detectLoop(head) ? "YES" : "NO") << endl;
    }
    return 0;
}
